import React, { useState } from "react";
import { BrowserRouter as Router, Routes, Route, Link, Navigate } from "react-router-dom";
import Home from "./Home";
import Register from "./pages/Register";
import Login from "./pages/Login";
import BMICalculator from "./pages/BMICalculator";
import BMIHistory from "./pages/BMIHistory";
import Dashboard from "./pages/Dashboard";
import AdminDashboard from "./pages/AdminDashboard";
import Chatbot from "./components/Chatbot";
import { useEffect } from "react";

function App() {
  const token = localStorage.getItem("token");
  const decoded = token ? JSON.parse(atob(token.split(".")[1])) : null;
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isDark, setIsDark] = useState(() => {
    if (localStorage.theme === 'dark' || (!localStorage.theme && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      document.documentElement.classList.add('dark');
      return true;
    }
    return false;
  });

  useEffect(() => {
    localStorage.setItem('theme', isDark ? 'dark' : 'light');
    if (isDark) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDark]);

  const toggleDark = () => setIsDark(!isDark);

  const handleLogout = () => {
    localStorage.removeItem("token");
    window.location.reload();
  };

  return (
    <Router>
      <div className="min-h-screen">
        {/* Enhanced Glassmorphism Navigation */}
        <nav className="glass glass-hover neon-glow sticky top-0 z-50 mx-4 mt-4 rounded-2xl shadow-2xl dark:shadow-glow-purple p-2">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between items-center h-16">
              {/* Logo */}
              <Link to="/" className="flex items-center space-x-2 group hover:scale-110 transition-all duration-300">
                <span className="text-2xl group-hover:animate-bounce">🤖</span>
                <span className="text-xl font-bold bg-gradient-to-r from-indigo-400 via-purple-400 to-pink-400 bg-clip-text text-transparent drop-shadow-neon">
                  BLACKBOX AI
                </span>
              </Link>

              {/* Desktop Navigation + Dark Toggle */}
              <div className="hidden md:flex items-center space-x-2">
                <Link to="/" className="px-4 py-2 rounded-xl text-gray-300 hover:bg-white/10 hover:text-indigo-300 glass-hover transition-all duration-300 font-medium">
                  Home
                </Link>

                {token && (
                  <Link to="/bmi" className="px-4 py-2 rounded-xl text-gray-300 hover:bg-white/10 hover:text-indigo-300 glass-hover transition-all duration-300 font-medium">
                    BlackBox BMI
                  </Link>
                )}

                {decoded?.role === "admin" && (
                  <Link to="/admin" className="px-4 py-2 rounded-xl text-purple-300 hover:bg-white/10 hover:text-purple-400 glass-hover transition-all duration-300 font-medium">
                    Admin
                  </Link>
                )}

                {token && (
                  <Link to="/dashboard" className="px-4 py-2 rounded-xl text-gray-300 hover:bg-white/10 hover:text-indigo-300 glass-hover transition-all duration-300 font-medium">
                    Dashboard
                  </Link>
                )}

                {token && (
                  <Link to="/bmi-history" className="px-4 py-2 rounded-xl text-gray-300 hover:bg-white/10 hover:text-indigo-300 glass-hover transition-all duration-300 font-medium">
                    History
                  </Link>
                )}

                {!token && (
                  <Link to="/register" className="px-4 py-2 rounded-xl text-gray-300 hover:bg-white/10 hover:text-indigo-300 glass-hover transition-all duration-300 font-medium">
                    Register
                  </Link>
                )}

                {/* Dark Toggle Button */}
                <button 
                  onClick={toggleDark}
                  className="ml-2 p-2 rounded-xl bg-white/10 hover:bg-white/20 glass-hover neon-glow transition-all duration-300 hover:rotate-12"
                  title="Toggle Dark Mode"
                >
                  {isDark ? (
                    <svg className="w-6 h-6 text-yellow-400" fill="currentColor" viewBox="0 0 20 20">
                      <path d="M17.293 13.293A8 8 0 016.707 2.707a8.001 8.001 0 1010.586 10.586z" />
                    </svg>
                  ) : (
                    <svg className="w-6 h-6 text-gray-900" fill="currentColor" viewBox="0 0 20 20">
                      <path fillRule="evenodd" d="M10 2a1 1 0 011 1v1a1 1 0 11-2 0V3a1 1 0 011-1zm4 8a4 4 0 11-8 0 4 4 0 018 0zm-.464 4.95l.707.707a1 1 0 001.414-1.414l-.707-.707a1 1 0 00-1.414 1.414zm2.12-10.607a1 1 0 010 1.414l-.706.707a1 1 0 11-1.414-1.414l.707-.707a1 1 0 011.414 0zM17 11a1 1 0 100-2h-1a1 1 0 100 2h1z" clipRule="evenodd" />
                    </svg>
                  )}
                </button>
                
                {!token ? (
                  <Link to="/login" className="ml-2 px-6 py-2.5 bg-gradient-to-r from-indigo-500 to-purple-600 text-white rounded-xl font-medium hover:shadow-neon-pulse hover:scale-105 active:scale-95 glass-hover neon-glow transition-all duration-300">
                    Login
                  </Link>
                ) : (
                  <button onClick={handleLogout} className="ml-2 px-4 py-2.5 bg-gradient-to-r from-rose-500 to-red-600 text-white rounded-xl font-medium hover:shadow-neon-pulse hover:scale-105 active:scale-95 glass-hover neon-glow transition-all duration-300">
                    Logout
                  </button>
                )}
              </div>

              {/* Dark Toggle Mobile */}
              <div className="flex items-center gap-1 md:hidden">
                <button onClick={toggleDark} className="p-1 rounded-lg hover:bg-white/10 transition-all">
                  {isDark ? '☀️' : '🌙'}
                </button>
                <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="md:hidden p-2 rounded-xl hover:bg-white/10 transition-all dark:text-white">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    {isMenuOpen ? (
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    ) : (
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                    )}
                  </svg>
                </button>
              </div>
            </div>

            {/* Mobile Navigation */}
            {isMenuOpen && (
              <div className="md:hidden pb-4 animate-slide-down bg-black/20 backdrop-blur-md rounded-b-2xl">
                <div className="flex flex-col space-y-2 p-2">
                  <Link to="/" className="px-4 py-2 rounded-xl text-gray-300 hover:bg-white/10 hover:text-indigo-300 transition-all" onClick={() => setIsMenuOpen(false)}>Home</Link>
                  {token && <Link to="/bmi" className="px-4 py-2 rounded-xl text-gray-300 hover:bg-white/10 hover:text-indigo-300 transition-all" onClick={() => setIsMenuOpen(false)}>BlackBox BMI</Link>}
                  {decoded?.role === "admin" && <Link to="/admin" className="px-4 py-2 rounded-xl text-purple-300 hover:bg-white/10 hover:text-purple-400 transition-all" onClick={() => setIsMenuOpen(false)}>Admin</Link>}
                  {token && <Link to="/dashboard" className="px-4 py-2 rounded-xl text-gray-300 hover:bg-white/10 hover:text-indigo-300 transition-all" onClick={() => setIsMenuOpen(false)}>Dashboard</Link>}
                  {token && <Link to="/bmi-history" className="px-4 py-2 rounded-xl text-gray-300 hover:bg-white/10 hover:text-indigo-300 transition-all" onClick={() => setIsMenuOpen(false)}>History</Link>}
                  {!token && <Link to="/register" className="px-4 py-2 rounded-xl text-gray-300 hover:bg-white/10 hover:text-indigo-300 transition-all" onClick={() => setIsMenuOpen(false)}>Register</Link>}
                  {!token && <Link to="/login" className="px-4 py-2 rounded-xl text-indigo-400 hover:bg-white/10 transition-all font-medium" onClick={() => setIsMenuOpen(false)}>Login</Link>}
{token && <button onClick={(e) => {handleLogout(); setIsMenuOpen(false);}} className="px-4 py-2 rounded-xl text-rose-400 hover:bg-rose-500/10 transition-all text-left font-medium">Logout</button>}
                </div>
              </div>
            )}
          </div>
        </nav>

        {/* Main Content with Animation */}
        <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6 animate-fade-in">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/bmi" element={token ? <BMICalculator /> : <Navigate to="/login" />} />
            <Route path="/register" element={<Register />} />
            <Route path="/login" element={<Login />} />
            <Route path="/dashboard" element={<Dashboard />} />
            <Route path="/admin" element={<AdminDashboard />} />
            <Route path="/bmi-history" element={token ? <BMIHistory /> : <Navigate to="/login" />} />
          </Routes>
        </main>

        {/* Chatbot - Shows on all pages after login */}
        {token && <Chatbot />}
      </div>
    </Router>
  );
}

export default App;
