import React, { useState, useRef, useEffect } from "react";
import axios from "axios";

// Quick suggestion buttons - BlackBox style
const quickSuggestions = [
  { label: "BMI Analysis", message: "Analyze my BMI status" },
  { label: "Health Risks", message: "What are my health risks?" },
  { label: "Weekly Plan", message: "Generate my weekly health plan" },
  { label: "Diet Tips", message: "Personalized diet recommendations" }
];

function Chatbot() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    {
      id: 1,
      role: "bot",
      text: "🔮 BlackBox AI Health activated. Ask anything about your health..."
    }
  ]);
  const [input, setInput] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isTyping]);

  // Focus input
  useEffect(() => {
    if (isOpen && inputRef.current) {
      setTimeout(() => inputRef.current.focus(), 300);
    }
  }, [isOpen]);

  const sendMessage = async (text) => {
    const messageToSend = text || input;
    if (!messageToSend.trim()) return;

    const userMessage = { id: Date.now(), role: "user", text: messageToSend.trim() };
    setMessages(prev => [...prev, userMessage]);
    setInput("");
    setIsTyping(true);

    try {
      const res = await axios.post("/api/health-ai/chat", { message: messageToSend.trim() });
      const botMessage = { id: Date.now() + 1, role: "bot", text: res.data.response };
      setMessages(prev => [...prev, botMessage]);
    } catch (err) {
      const errorMessage = { 
        id: Date.now() + 1, 
        role: "bot", 
        text: "⚠️ BlackBox processing error. Try different query." 
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const handleSuggestion = (suggestion) => sendMessage(suggestion.message);

  const toggleChat = () => setIsOpen(!isOpen);

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {/* Chat Window - Dark Glass */}
      <div className={`absolute bottom-16 right-0 w-80 md:w-96 glass glass-hover neon-glow shadow-2xl overflow-hidden transition-all duration-500 transform ${
        isOpen ? "opacity-100 scale-100 translate-y-0" : "opacity-0 scale-90 -translate-y-4 pointer-events-none"
      }`} style={{ maxHeight: "70vh" }}>
        
        {/* Header */}
        <div className="glass-dark p-5 flex items-center justify-between border-b border-white/10">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-2xl flex items-center justify-center shadow-glow-purple animate-pulse">
              <span className="text-2xl">🤖</span>
            </div>
            <div>
              <h3 className="text-white font-black text-xl bg-gradient-to-r from-indigo-400 to-purple-400 bg-clip-text">
                BlackBox Health AI
              </h3>
              <p className="text-gray-400 text-xs">Neon intelligence activated</p>
            </div>
          </div>
          <button
            onClick={toggleChat}
            className="p-2 hover:bg-white/10 rounded-xl transition-all hover:rotate-90 hover:scale-110 neon-glow"
          >
            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Messages Area */}
        <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-black/20">
{messages.map((msg) => (
            <div
              key={msg.id}
              className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"} animate-slide-up`}
            >
              <div className={`max-w-[75%] p-4 rounded-2xl text-sm shadow-lg neon-glow ${
                msg.role === "user"
                  ? "bg-gradient-to-r from-indigo-500 to-purple-600 text-white rounded-br-none shadow-glow-purple"
                  : "bg-white/10 backdrop-blur-xl text-gray-100 rounded-bl-none border border-white/20 shadow-glow-blue"
              }`}>
                {msg.text}
              </div>
            </div>
          ))}

          {/* Enhanced Typing Indicator */}
          {isTyping && (
            <div className="flex justify-start animate-slide-up">
              <div className="bg-white/10 backdrop-blur-xl p-4 rounded-2xl rounded-bl-none border border-indigo-500/30 shadow-glow-blue">
                <div className="flex items-center gap-3">
                  <div className="flex gap-1">
                    <div className="w-2.5 h-2.5 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '0ms'}} />
                    <div className="w-2.5 h-2.5 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '200ms'}} />
                    <div className="w-2.5 h-2.5 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '400ms'}} />
                  </div>
                  <div className="h-1 w-16 bg-gradient-to-r from-transparent via-indigo-400 to-transparent animate-scan rounded-full" />
                </div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Quick Suggestions */}
        <div className="px-4 py-3 bg-white/5 border-t border-white/10 flex gap-2 overflow-x-auto">
          {quickSuggestions.map((suggestion, index) => (
            <button
              key={index}
              onClick={() => handleSuggestion(suggestion)}
              className="flex-shrink-0 px-4 py-2 bg-white/10 hover:bg-white/20 backdrop-blur-sm text-indigo-300 hover:text-white text-xs font-bold rounded-full border border-indigo-500/30 hover:border-indigo-400/50 neon-glow transition-all hover:scale-105 whitespace-nowrap"
            >
              {suggestion.label}
            </button>
          ))}
        </div>

        {/* Input Area */}
        <div className="p-5 bg-white/5 border-t border-white/10">
          <div className="flex gap-3 items-end">
            <input
              ref={inputRef}
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Describe your health concern..."
              className="flex-1 px-5 py-4 bg-white/5 backdrop-blur-md rounded-2xl border-2 border-white/10 focus:border-indigo-400 focus:ring-4 focus:ring-indigo-500/30 text-white placeholder-gray-400 transition-all duration-300 hover:border-white/20 text-lg font-medium focus:scale-105 neon-glow"
              disabled={isTyping}
            />
            <button
              onClick={() => sendMessage()}
              disabled={!input.trim() || isTyping}
              className="p-4 bg-gradient-to-br from-indigo-500 to-purple-600 hover:from-indigo-400 hover:to-purple-500 text-white rounded-2xl shadow-neon-glow hover:shadow-neon-pulse hover:scale-110 active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed transition-all duration-300 neon-glow group"
            >
              <svg className="w-6 h-6 group-hover:rotate-12 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
            </button>
          </div>
        </div>
      </div>

      {/* Floating Chat Button - Neon */}
      <button
        onClick={toggleChat}
        className="w-16 h-16 glass-dark shadow-2xl neon-glow hover:shadow-neon-pulse hover:scale-125 active:scale-95 transition-all duration-300 hover:rotate-180 group relative overflow-hidden"
      >
        <div className="absolute inset-0 bg-gradient-to-r from-indigo-500/0 to-purple-500/0 group-hover:from-indigo-500/30 group-hover:to-purple-500/30 transition-all duration-300 rounded-3xl" />
        <span className={`text-2xl transition-all ${isOpen ? 'rotate-180' : ''}`}>
          {isOpen ? '✕' : '💬'}
        </span>
      </button>
    </div>
  );
}

export default Chatbot;
